DELETE FROM vehicle_maintenance_logs
WHERE log_id IN (
SELECT log_id FROM (
SELECT log_id,
ROW_NUMBER() OVER (ORDER BY maintenance_date DESC, cost ASC) AS rn
FROM vehicle_maintenance_logs
WHERE cost > 1000
) ranked
WHERE rn > 2 AND rn <= 7
);

